fZ z1_eval(fEta aeta, fEta eta, fEta s1) {
  #pragma HLS INLINE off
  // Horner form, reuse s1 precomputed
  fZ z;
  if (aeta < 0.8) {
    // (1558.859292 - 4.990838*a - 21.144279*a^2) * s1
    z = CalcSecondOrder(aeta, C0_L1E08, C1_L1E08, C2_L1E08);
    z *= s1;
  } else if (aeta < 1.5) {
    // (1522.775373 + 27.970192*a - 21.104108*a^2) * s1
    z = CalcSecondOrder(aeta, C0_L1E15, C1_L1E15, C2_L1E15);
    z *= s1;
  } else {
    z = CalcSecondOrder(aeta, C0_L1E25, CZero, CZero);
    if (eta < 0) {z *= -1;}
  }
  return z;
}

fZ z2_eval(fEta aeta, fEta eta, fEta s2) {
  #pragma HLS INLINE off
  fZ z;
  if (aeta < 1.425) {
    // (1698.990944 - 49.431767*a - 24.504976*a^2) * s2
    z = CalcSecondOrder(aeta, C0_L2E1425, C1_L2E1425, C2_L2E1425);
    z *= s2;
  } else if (aeta < 1.5) {
    // (8027.574119 - 2717.653528*a) * s2
    z = CalcSecondOrder(aeta, C0_L2E15, C1_L2E15, CZero);
    z *= s2;
  } else {
    z = CalcSecondOrder(aeta, C0_L2E25, C1_L2E25, C2_L2E25);
    if (eta < 0) z = -z;
  }
  return z;
}


fZ CalcSecondOrder(fEta aeta, fZ c0, fZ c1, fZ c2){
    return ((c2 * aeta) + c1) * aeta + c0;
}

fZ PPZ_calc(int eta1Idx, int eta2Idx){
  #pragma HLS PIPELINE II=1
  #pragma HLS INLINE off


  #pragma HLS bind_storage variable=EtaL1Map type=ram_2p impl=URAM // Save SinhMap as URAM 2 port memory RAM (ROM not allowed w/ URAM)
  #pragma HLS bind_storage variable=EtaL2Map type=ram_2p impl=URAM // Save EtaIdxMap as URAM 2 port memory RAM (ROM not allowed w/ URAM)
  #pragma HLS bind_storage variable=SinHL1Map type=ram_2p impl=URAM // Save SinhMap as URAM 2 port memory RAM (ROM not allowed w/ URAM)
  #pragma HLS bind_storage variable=SinHL2Map type=ram_2p impl=URAM // Save EtaIdxMap as URAM 2 port memory RAM (ROM not allowed w/ URAM)
  #pragma HLS bind_storage variable=PhiMap type=ram_2p impl=URAM // Save EtaIdxMap as URAM 2 port memory RAM (ROM not allowed w/ URAM)

  if ((eta1Idx == EtaIdxOverFlow) or (eta2Idx == EtaIdxOverFlow) or (eta1Idx == eta2Idx)){return PPZOverFlow;} // We can maybe recover eta1 == eta2....


  fEta eta1 = EtaL1Map[eta1Idx];
  fEta eta2 = EtaL2Map[eta2Idx];


  fEta aeta1 = hls::abs(eta1);
  fEta aeta2 = hls::abs(eta2);
          
  fEta s1 = SinHL1Map[eta1Idx];
  fEta s2 = SinHL2Map[eta2Idx];

    // #pragma HLS bind_op variable=aeta1 op=hmul
    // #pragma HLS bind_op variable=aeta2 op=hmul

    fZ Z1 = z1_eval(aeta1, eta1, s1);
    fZ Z2 = z2_eval(aeta2, eta2, s2);

  // Z1 * Z2 * (s1 - s2) / Z2*s1 - Z1*s2   = Z1 * a - Z2 * b / a - b
  //

    // Single reciprocal instead of division
    fZ num = ((Z1 * Z2) * (s1 - s2));
    fZ den = (Z2 * s1) - (Z1 * s2);

    // fZ Z1S2 = Z1 * s2;
    // fZ Z2S1 = Z2 * s1;

    // fZ num = Z1 * Z2S1 - Z2 * Z1S2;
    // fZ den = Z2S1 - Z1S2;


    fZ PPZ = num/den;

    #ifndef __SYNTHESIS__
    std::cout << "e1Idx = " << eta1Idx << ", e2Idx = " << eta2Idx << std::endl;
    std::cout << "e1 = " << eta1 << ", e2 = " << eta2 << std::endl;
    std::cout << "s1 = " << s1 << ", s2 = " << s2 << std::endl;
    // std::cout << "Z1, Z2 = " << Z1 << ", " << Z2 << std::endl;
    // std::cout << "num = " << num << ", den = " << den << ", num/den = " << num/den << std::endl;
    std::cout << "PPZ = " << PPZ << std::endl;
    #endif
    return (PPZ);
}
